import{_ as e,c as a,o as l,ag as t}from"./chunks/framework.mFrY8Rqo.js";const p=JSON.parse('{"title":"帮助与反馈","description":"","frontmatter":{},"headers":[],"relativePath":"guide/help.md","filePath":"guide/help.md","lastUpdated":1742406294000}'),s={name:"guide/help.md"};function r(o,i,u,c,d,h){return l(),a("div",null,i[0]||(i[0]=[t('<h1 id="帮助与反馈" tabindex="-1">帮助与反馈 <a class="header-anchor" href="#帮助与反馈" aria-label="Permalink to &quot;帮助与反馈&quot;">​</a></h1><h2 id="提问的艺术" tabindex="-1">提问的艺术 <a class="header-anchor" href="#提问的艺术" aria-label="Permalink to &quot;提问的艺术&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>当你提出一个技术问题时，最终是否能得到有用的回答，往往取决于你所提问和追问的方式。</p></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>好的提问应包含：</strong></p><ul><li>你的环境信息（操作系统、biliup 版本号、安装方式）</li><li>你做了什么操作（具体命令或 WebUI 步骤）</li><li>期望的结果是什么</li><li>实际发生了什么（附带错误日志！）</li><li>你已经尝试过哪些解决方案</li></ul></div><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p>请尊重开发者的无偿付出。我们欢迎友好且有建设性的交流。</p></div><hr><h2 id="反馈渠道" tabindex="-1">反馈渠道 <a class="header-anchor" href="#反馈渠道" aria-label="Permalink to &quot;反馈渠道&quot;">​</a></h2><h3 id="github-issues-推荐" tabindex="-1">GitHub Issues（推荐） <a class="header-anchor" href="#github-issues-推荐" aria-label="Permalink to &quot;GitHub Issues（推荐）&quot;">​</a></h3><p>在 <a href="https://github.com/biliup/biliup/issues" target="_blank" rel="noreferrer">biliup/biliup Issues</a> 提交 Issue 是最高效的反馈方式。</p><p>提交前请：</p><ol><li>搜索已有 Issue，确认是否为已知问题</li><li>使用 Issue 模板</li><li>附上相关日志（<code>ds_update.log</code>、<code>upload.log</code> 等）</li></ol><h3 id="即时交流" tabindex="-1">即时交流 <a class="header-anchor" href="#即时交流" aria-label="Permalink to &quot;即时交流&quot;">​</a></h3><ul><li>QQ 群 / Telegram 群（详见 <a href="https://biliup.me" target="_blank" rel="noreferrer">biliup 社区</a>）</li><li>在群内提问前，建议先阅读本文档</li></ul><hr><h2 id="常见问题快速入口" tabindex="-1">常见问题快速入口 <a class="header-anchor" href="#常见问题快速入口" aria-label="Permalink to &quot;常见问题快速入口&quot;">​</a></h2><ul><li><a href="/biliup-docs/guide/introduce/introduce/Linux.html">安装问题</a></li><li><a href="/biliup-docs/guide/introduce/quickstart/get-start.html">录制配置</a></li><li><a href="/biliup-docs/guide/introduce/introduce/faq.html">Q&amp;A 常见问题</a></li><li><a href="/biliup-docs/guide/configs/config.html">CLI 命令参考</a></li></ul>',16)]))}const b=e(s,[["render",r]]);export{p as __pageData,b as default};
